select case @ky_pt
  when '1' then case when @@language = 'V' then N'Tháng' else 'Month' end
  when '2' then case when @@language = 'V' then N'Quý' else 'Quarter' end
  when '3' then case when @@language = 'V' then N'6 tháng' else 'Half a year' end
  when '4' then case when @@language = 'V' then N'Năm' else 'Year' end
end as kieu_bc, @bc_theo as bc_theo, @tu_ngay as tu_ngay
exec rs_rptExpensesAggregationMultiPeriod @tu_ngay, @ky_pt, @so_ky, @ds_tk, @loai, @ds_tk_gt, @bc_theo, @nhom_theo1, @nhom_theo2, @nh_phi1, @nh_phi2, @nh_phi3, @mau_bc, @ma_dvcs, @@language, @@userID, @@admin







      &JavascriptPivotFilter;
      &OutlineEntry;
      &ScriptQueryFilterString;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {
  sender.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(sender, 'ma_dvcs');
  changeLookupReadonly(sender, 'ds_tk');
  changeLookupReadonly(sender, 'ds_tk_gt');
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc'), dFrom = f.getItem('tu_ngay').value, reportBy = f.getItem('ky_pt').value, periodNo = f.getItem('so_ky').value, h = f.getItem('bc_theo'), v = g._language == 'v', r;
      switch (reportBy) {
      case '1':
        r = (v ? 'theo tháng' : 'by Month');
        break;
      case '2':
        r = (v ? 'theo quý' : 'by Quarter');
        break;
      case '3':
        r = (v ? 'theo 6 tháng' : 'by Half a Year');
        break;
      case '4':
        r = (v ? 'theo năm' : 'by Year');
        break;
      default:
        break;
      }
      g._pivotFieldHeaderText = h.value == 3 && v ? 'Đơn vị' : h.options[h.selectedIndex].text;
      g._alterTitle = [null, [['%s1', r, true], ['%s2', periodNo, true], ['%d', dFrom, true]]];
      g._queryFilterString = getQueryFilterString(f, 'tu_ngay, ky_pt, so_ky, bc_theo, ma_dvcs, mau_bc, nhom_theo1, nhom_theo2, nh_phi1, nh_phi2, nh_phi3, ds_tk, ds_tk_gt, loai');

      var c = periodNo + String.fromCharCode(255) + x;
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
